INSERT INTO plugin_catalog (slug, name, description, version, category, tool_manifest, source_repo, source, verified) VALUES ('lucid-audit', 'Lucid Audit', 'Smart contract security: vulnerability scanning, risk scoring, compliance checks', '2.0.0', 'security', '[{"name":"audit_scan_contract","description":"Scan Solidity source code for vulnerabilities. Performs pattern-based detection of reentrancy, access control, overflow, unchecked returns, front-running, oracle manipulation, flash loan, logic errors, and centralization issues.","parameters":{"type":"object","properties":{"source_code":{"type":"string","description":"Solidity source code to analyze"},"contract_name":{"type":"string","description":"Name of the contract (for reporting)"}},"required":["source_code"],"additionalProperties":false,"$schema":"http://json-schema.org/draft-07/schema#"}},{"name":"audit_get_security_score","description":"Calculate a security score (0-100) for Solidity source code with detailed breakdown by severity.","parameters":{"type":"object","properties":{"source_code":{"type":"string","description":"Solidity source code to score"}},"required":["source_code"],"additionalProperties":false,"$schema":"http://json-schema.org/draft-07/schema#"}},{"name":"audit_check_reentrancy","description":"Check Solidity source code specifically for reentrancy vulnerabilities including cross-function reentrancy.","parameters":{"type":"object","properties":{"source_code":{"type":"string","description":"Solidity source code to check"}},"required":["source_code"],"additionalProperties":false,"$schema":"http://json-schema.org/draft-07/schema#"}},{"name":"audit_check_access_control","description":"Analyze Solidity source code for access control issues: unprotected selfdestruct, missing access control on sensitive functions, tx.origin misuse.","parameters":{"type":"object","properties":{"source_code":{"type":"string","description":"Solidity source code to check"}},"required":["source_code"],"additionalProperties":false,"$schema":"http://json-schema.org/draft-07/schema#"}},{"name":"audit_analyze_gas","description":"Analyze Solidity source code for gas optimization opportunities including storage patterns, loop optimization, packing, and visibility improvements.","parameters":{"type":"object","properties":{"source_code":{"type":"string","description":"Solidity source code to analyze"}},"required":["source_code"],"additionalProperties":false,"$schema":"http://json-schema.org/draft-07/schema#"}},{"name":"audit_verify_contract","description":"Check if a contract address is verified on a block explorer (Etherscan and compatible explorers).","parameters":{"type":"object","properties":{"address":{"type":"string","description":"Contract address (0x...)"},"chain":{"type":"string","enum":["ethereum","bsc","polygon","arbitrum","optimism","avalanche","base"],"description":"Blockchain network (default: ethereum)"}},"required":["address"],"additionalProperties":false,"$schema":"http://json-schema.org/draft-07/schema#"}},{"name":"audit_get_audit_report","description":"Generate a comprehensive audit report including vulnerability scan, gas analysis, security score, and function analysis.","parameters":{"type":"object","properties":{"source_code":{"type":"string","description":"Solidity source code to audit"},"contract_name":{"type":"string","description":"Name of the contract"}},"required":["source_code"],"additionalProperties":false,"$schema":"http://json-schema.org/draft-07/schema#"}},{"name":"audit_list_audits","description":"List previous audits with optional filters by contract ID, status, and pagination.","parameters":{"type":"object","properties":{"contract_id":{"type":"string","description":"Filter by contract ID"},"status":{"type":"string","enum":["pending","in_progress","completed","failed"],"description":"Filter by audit status"},"limit":{"type":"number","minimum":1,"maximum":100,"description":"Max results to return (default: 20)"}},"additionalProperties":false,"$schema":"http://json-schema.org/draft-07/schema#"}},{"name":"audit_compare_contracts","description":"Compare two versions of a contract to identify security improvements or regressions.","parameters":{"type":"object","properties":{"source_a":{"type":"string","description":"Source code of the first (older) version"},"source_b":{"type":"string","description":"Source code of the second (newer) version"},"label_a":{"type":"string","description":"Label for version A (default: \"Version A\")"},"label_b":{"type":"string","description":"Label for version B (default: \"Version B\")"}},"required":["source_a","source_b"],"additionalProperties":false,"$schema":"http://json-schema.org/draft-07/schema#"}},{"name":"audit_check_upgradability","description":"Analyze Solidity source code for proxy and upgradability patterns including transparent proxy, UUPS, and beacon patterns.","parameters":{"type":"object","properties":{"source_code":{"type":"string","description":"Solidity source code to analyze"}},"required":["source_code"],"additionalProperties":false,"$schema":"http://json-schema.org/draft-07/schema#"}},{"name":"audit_get_known_vulnerabilities","description":"Check contract source code against a database of known vulnerability patterns (SWC registry).","parameters":{"type":"object","properties":{"source_code":{"type":"string","description":"Solidity source code to check"}},"required":["source_code"],"additionalProperties":false,"$schema":"http://json-schema.org/draft-07/schema#"}},{"name":"audit_analyze_dependencies","description":"Analyze import statements and library dependencies in Solidity source code for potential security concerns.","parameters":{"type":"object","properties":{"source_code":{"type":"string","description":"Solidity source code to analyze"}},"required":["source_code"],"additionalProperties":false,"$schema":"http://json-schema.org/draft-07/schema#"}},{"name":"audit_generate_findings","description":"Generate a structured findings document in a standard audit report format, suitable for sharing with development teams.","parameters":{"type":"object","properties":{"source_code":{"type":"string","description":"Solidity source code to analyze"},"contract_name":{"type":"string","description":"Name of the contract"},"auditor":{"type":"string","description":"Name of the auditor or team"}},"required":["source_code"],"additionalProperties":false,"$schema":"http://json-schema.org/draft-07/schema#"}},{"name":"audit_status","description":"System health and configuration status: version info, configured providers, database connection, and settings.","parameters":{"type":"object","properties":{},"$schema":"http://json-schema.org/draft-07/schema#"}},{"name":"lucid_audit","description":"Deep security audit of a Solidity contract. Runs all 9 vulnerability detectors + 6 gas analyzers and returns a structured AuditResult with verdict (SAFE / CAUTION / RISKY / CRITICAL), score (0-100), grade (A-F), top vulnerabilities, gas analysis, and risk factors.","parameters":{"type":"object","properties":{"source_code":{"type":"string","description":"Solidity source code to audit"},"contract_name":{"type":"string","description":"Name of the contract (for reporting)"},"chain":{"type":"string","description":"Chain the contract is deployed on (ethereum, bsc, polygon, etc.)"},"address":{"type":"string","description":"Deployed contract address (for reporting)"},"format":{"type":"string","enum":["json","text"],"description":"Output format: json (structured) or text (human-readable)"},"detail":{"type":"string","enum":["full","compact"],"description":"Detail level: full includes all vulnerabilities and gas details, compact omits them"}},"required":["source_code","contract_name","chain","address","format","detail"],"additionalProperties":false,"$schema":"http://json-schema.org/draft-07/schema#"}},{"name":"lucid_audit_compare","description":"Compare two contract versions to identify fixed, new, and persistent security issues. Shows score delta and overall trend (IMPROVED / REGRESSED / UNCHANGED).","parameters":{"type":"object","properties":{"source_a":{"type":"string","description":"Source code of the first (older) version"},"source_b":{"type":"string","description":"Source code of the second (newer) version"},"label_a":{"type":"string","description":"Label for version A (default: \"Version A\")"},"label_b":{"type":"string","description":"Label for version B (default: \"Version B\")"},"format":{"type":"string","enum":["json","text"],"description":"Output format"}},"required":["source_a","source_b","label_a","label_b","format"],"additionalProperties":false,"$schema":"http://json-schema.org/draft-07/schema#"}},{"name":"lucid_audit_batch","description":"Batch scan multiple contracts and return aggregate scores, verdicts, and finding counts. Identifies the worst contract in the set.","parameters":{"type":"object","properties":{"contracts":{"type":"array","items":{"type":"object","properties":{"source":{"type":"string","description":"Solidity source code"},"name":{"type":"string","description":"Contract name"}},"required":["source","name"],"additionalProperties":false},"description":"Array of {source, name} objects representing contracts to scan"},"format":{"type":"string","enum":["json","text"],"description":"Output format"}},"required":["contracts","format"],"additionalProperties":false,"$schema":"http://json-schema.org/draft-07/schema#"}},{"name":"lucid_gas","description":"Focused gas optimization analysis of Solidity source code. Detects storage inefficiencies, loop issues, packing problems, visibility improvements, and more. Returns structured results with estimated savings per issue.","parameters":{"type":"object","properties":{"source_code":{"type":"string","description":"Solidity source code to analyze"},"format":{"type":"string","enum":["json","text"],"description":"Output format"}},"required":["source_code","format"],"additionalProperties":false,"$schema":"http://json-schema.org/draft-07/schema#"}},{"name":"lucid_audit_pro","description":"Direct access to individual vulnerability detectors and gas analyzers. Use list_tools to see available tools, or call one directly with source_code in params.","parameters":{"type":"object","properties":{"tool":{"type":"string","description":"Tool name or \"list_tools\" to see available tools"},"params":{"type":"object","additionalProperties":{},"description":"Tool parameters — typically {source_code: \"...\"}"}},"required":["tool","params"],"additionalProperties":false,"$schema":"http://json-schema.org/draft-07/schema#"}}]'::jsonb, 'raijinlabs/lucid-skills', 'first-party', true) ON CONFLICT (slug) DO UPDATE SET name=EXCLUDED.name, description=EXCLUDED.description, version=EXCLUDED.version, category=EXCLUDED.category, tool_manifest=EXCLUDED.tool_manifest, source_repo=EXCLUDED.source_repo, source=EXCLUDED.source, verified=EXCLUDED.verified;
INSERT INTO plugin_catalog (slug, name, description, version, category, tool_manifest, source_repo, source, verified) VALUES ('lucid-bridge', 'Lucid Bridge', 'Startup ops integration: Notion, Linear, Slack, GitHub orchestration', '1.0.0', 'operations', '[{"name":"bridge_create_workflow","description":"Create an automation workflow with a trigger platform/event and one or more actions across platforms.","parameters":{"type":"object","properties":{"name":{"type":"string","description":"Workflow name"},"trigger_platform":{"type":"string","enum":["notion","linear","slack","github","jira","google_workspace","discord","trello"],"description":"Platform that triggers the workflow"},"trigger_event":{"type":"string","description":"Event that triggers the workflow (e.g., issue_created, pr_opened, message_posted)"},"actions":{"type":"array","items":{"type":"object","additionalProperties":{},"description":"Action definition with platform, action type, and params"},"description":"List of actions to execute"}},"required":["name","trigger_platform","trigger_event","actions"],"additionalProperties":false,"$schema":"http://json-schema.org/draft-07/schema#"}},{"name":"bridge_list_workflows","description":"List automation workflows with optional status filter.","parameters":{"type":"object","properties":{"status":{"type":"string","enum":["active","paused","error","draft"],"description":"Filter by workflow status"}},"additionalProperties":false,"$schema":"http://json-schema.org/draft-07/schema#"}},{"name":"bridge_run_workflow","description":"Execute a workflow manually by providing a workflow ID and optional trigger data.","parameters":{"type":"object","properties":{"workflow_id":{"type":"string","description":"ID of the workflow to execute"},"trigger_data":{"type":"object","additionalProperties":{},"description":"Data to pass as trigger context"}},"required":["workflow_id"],"additionalProperties":false,"$schema":"http://json-schema.org/draft-07/schema#"}},{"name":"bridge_create_connection","description":"Set up a platform connection (Slack, GitHub, Notion, Linear, Jira, etc.).","parameters":{"type":"object","properties":{"platform":{"type":"string","enum":["notion","linear","slack","github","jira","google_workspace","discord","trello"],"description":"Platform to connect"},"account_name":{"type":"string","description":"Friendly name for this connection"},"config":{"type":"object","additionalProperties":{},"description":"Platform-specific configuration (tokens, keys, etc.)"}},"required":["platform","account_name"],"additionalProperties":false,"$schema":"http://json-schema.org/draft-07/schema#"}},{"name":"bridge_list_connections","description":"List configured platform connections with their status.","parameters":{"type":"object","properties":{"platform":{"type":"string","enum":["notion","linear","slack","github","jira","google_workspace","discord","trello"],"description":"Filter by platform"}},"additionalProperties":false,"$schema":"http://json-schema.org/draft-07/schema#"}},{"name":"bridge_sync_data","description":"Sync data between two platforms. Creates a sync mapping and performs the sync.","parameters":{"type":"object","properties":{"mapping_id":{"type":"string","description":"Existing mapping ID to sync (if re-syncing)"},"source_platform":{"type":"string","enum":["notion","linear","slack","github","jira","google_workspace","discord","trello"],"description":"Source platform"},"source_id":{"type":"string","description":"Source entity ID"},"target_platform":{"type":"string","enum":["notion","linear","slack","github","jira","google_workspace","discord","trello"],"description":"Target platform"},"target_id":{"type":"string","description":"Target entity ID"},"entity_type":{"type":"string","enum":["task","document","message","issue","pr","page","channel"],"description":"Type of entity being synced"},"direction":{"type":"string","enum":["bidirectional","source_to_target","target_to_source"],"description":"Sync direction"}},"additionalProperties":false,"$schema":"http://json-schema.org/draft-07/schema#"}},{"name":"bridge_get_logs","description":"Get workflow execution and sync logs, optionally filtered by mapping.","parameters":{"type":"object","properties":{"mapping_id":{"type":"string","description":"Filter logs by sync mapping ID"},"errors_only":{"type":"boolean","description":"Show only error logs"},"limit":{"type":"number","description":"Maximum number of logs to return"}},"additionalProperties":false,"$schema":"http://json-schema.org/draft-07/schema#"}},{"name":"bridge_create_webhook","description":"Create an incoming webhook endpoint for triggering workflows from external sources.","parameters":{"type":"object","properties":{"name":{"type":"string","description":"Webhook name"},"platform":{"type":"string","enum":["notion","linear","slack","github","jira","google_workspace","discord","trello"],"description":"Associated platform"},"event":{"type":"string","description":"Event type this webhook listens for"},"workflow_id":{"type":"string","description":"Workflow to trigger when webhook is called"}},"required":["name","platform","event"],"additionalProperties":false,"$schema":"http://json-schema.org/draft-07/schema#"}},{"name":"bridge_transform_data","description":"Transform data between platform formats (e.g., Linear issue to GitHub issue, Notion page to Jira task).","parameters":{"type":"object","properties":{"data":{"type":"object","additionalProperties":{},"description":"The source data to transform"},"source_platform":{"type":"string","enum":["notion","linear","slack","github","jira","google_workspace","discord","trello"],"description":"Platform the data comes from"},"target_platform":{"type":"string","enum":["notion","linear","slack","github","jira","google_workspace","discord","trello"],"description":"Platform to transform the data for"},"entity_type":{"type":"string","enum":["task","document","message","issue","pr","page","channel"],"description":"Type of entity"}},"required":["data","source_platform","target_platform"],"additionalProperties":false,"$schema":"http://json-schema.org/draft-07/schema#"}},{"name":"bridge_schedule_workflow","description":"Schedule a workflow for recurring execution using a cron expression.","parameters":{"type":"object","properties":{"workflow_id":{"type":"string","description":"ID of the workflow to schedule"},"schedule":{"type":"string","description":"Cron expression for schedule (e.g., \"*/30 * * * *\" for every 30 minutes)"},"enabled":{"type":"boolean","description":"Whether to enable or disable the schedule"}},"required":["workflow_id","schedule"],"additionalProperties":false,"$schema":"http://json-schema.org/draft-07/schema#"}},{"name":"bridge_get_metrics","description":"Get workflow execution metrics, sync stats, and overall system statistics.","parameters":{"type":"object","properties":{},"$schema":"http://json-schema.org/draft-07/schema#"}},{"name":"bridge_status","description":"System health and status: connected platforms, configuration, and uptime info.","parameters":{"type":"object","properties":{},"$schema":"http://json-schema.org/draft-07/schema#"}}]'::jsonb, 'raijinlabs/lucid-skills', 'first-party', true) ON CONFLICT (slug) DO UPDATE SET name=EXCLUDED.name, description=EXCLUDED.description, version=EXCLUDED.version, category=EXCLUDED.category, tool_manifest=EXCLUDED.tool_manifest, source_repo=EXCLUDED.source_repo, source=EXCLUDED.source, verified=EXCLUDED.verified;
INSERT INTO plugin_catalog (slug, name, description, version, category, tool_manifest, source_repo, source, verified) VALUES ('lucid-compete', 'Lucid Compete', 'Competitive intelligence: market monitoring, battle cards, real-time alerts', '1.0.0', 'intelligence', '[{"name":"compete_add_competitor","description":"Add a new competitor to track. Automatically discovers monitorable endpoints (pricing pages, RSS feeds).","parameters":{"type":"object","properties":{"name":{"type":"string","description":"The name of the competitor"},"website":{"type":"string","description":"The competitor website URL (e.g. https://example.com)"},"description":{"type":"string","description":"A brief description of the competitor"},"industry":{"type":"string","description":"The industry the competitor operates in"}},"required":["name","website"],"$schema":"http://json-schema.org/draft-07/schema#"}},{"name":"compete_list_competitors","description":"List all tracked competitors, optionally filtered by industry.","parameters":{"type":"object","properties":{"industry":{"type":"string","description":"Filter by industry"}},"$schema":"http://json-schema.org/draft-07/schema#"}},{"name":"compete_update_competitor","description":"Update an existing competitor''s details.","parameters":{"type":"object","properties":{"id":{"type":"number","description":"The competitor ID to update"},"name":{"type":"string","description":"New name for the competitor"},"website":{"type":"string","description":"New website URL"},"description":{"type":"string","description":"New description"},"industry":{"type":"string","description":"New industry"}},"required":["id"],"$schema":"http://json-schema.org/draft-07/schema#"}},{"name":"compete_remove_competitor","description":"Remove a competitor and all associated monitors and signals (cascading delete).","parameters":{"type":"object","properties":{"id":{"type":"number","description":"The competitor ID to remove"}},"required":["id"],"$schema":"http://json-schema.org/draft-07/schema#"}},{"name":"compete_add_monitor","description":"Add a new monitor to track a specific source for a competitor.","parameters":{"type":"object","properties":{"competitor_id":{"type":"number","description":"The competitor ID this monitor belongs to"},"monitor_type":{"type":"string","enum":["web-diff","github","rss","jobs","npm","twitter","reddit","producthunt","g2","crunchbase","linkedin","hackernews"],"description":"The type of monitor source"},"url":{"type":"string","description":"The URL to monitor"},"config":{"type":"object","propertyNames":{"type":"string"},"additionalProperties":{},"description":"Optional configuration for the monitor"},"enabled":{"type":"boolean","description":"Whether the monitor is enabled (default: true)"}},"required":["competitor_id","monitor_type","url"],"$schema":"http://json-schema.org/draft-07/schema#"}},{"name":"compete_list_monitors","description":"List monitors, optionally filtered by competitor or enabled status.","parameters":{"type":"object","properties":{"competitor_id":{"type":"number","description":"Filter monitors by competitor ID"},"enabled_only":{"type":"boolean","description":"Show only enabled monitors"}},"$schema":"http://json-schema.org/draft-07/schema#"}},{"name":"compete_remove_monitor","description":"Remove a monitor by ID.","parameters":{"type":"object","properties":{"id":{"type":"number","description":"The monitor ID to remove"}},"required":["id"],"$schema":"http://json-schema.org/draft-07/schema#"}},{"name":"compete_fetch_now","description":"Fetch the latest data from monitors immediately. Can target a specific monitor, all monitors for a competitor, or all enabled monitors.","parameters":{"type":"object","properties":{"competitor_id":{"type":"number","description":"Fetch all monitors for this competitor"},"monitor_id":{"type":"number","description":"Fetch only this specific monitor"}},"$schema":"http://json-schema.org/draft-07/schema#"}},{"name":"compete_list_signals","description":"List competitive signals with optional filters by competitor, severity, type, and date range.","parameters":{"type":"object","properties":{"competitor_id":{"type":"number","description":"Filter signals by competitor ID"},"severity":{"type":"string","enum":["low","medium","high","critical"],"description":"Filter by severity level"},"signal_type":{"type":"string","enum":["pricing_change","feature_launch","funding_round","new_hire","job_posting","release","review","social_mention","news","content_change","other"],"description":"Filter by signal type"},"limit":{"type":"number","description":"Maximum number of signals to return (default: 50)"},"days_back":{"type":"number","description":"Only show signals from the last N days (default: 30)"}},"$schema":"http://json-schema.org/draft-07/schema#"}},{"name":"compete_generate_battlecard","description":"Generate a competitive battlecard for a specific competitor based on recent signals.","parameters":{"type":"object","properties":{"competitor_id":{"type":"number","description":"The competitor ID to generate a battlecard for"},"days_back":{"type":"number","description":"Number of days of signal history to include (default: 30)"}},"required":["competitor_id"],"$schema":"http://json-schema.org/draft-07/schema#"}},{"name":"compete_generate_brief","description":"Generate a competitive intelligence brief (weekly or monthly) summarizing recent signals across all competitors.","parameters":{"type":"object","properties":{"brief_type":{"type":"string","enum":["weekly","monthly"],"description":"The type of brief to generate"},"date":{"type":"string","description":"The date for the brief (YYYY-MM-DD, defaults to today)"}},"required":["brief_type"],"$schema":"http://json-schema.org/draft-07/schema#"}},{"name":"compete_search","description":"Full-text search across all competitive signals (title, summary, content).","parameters":{"type":"object","properties":{"query":{"type":"string","description":"The search query"},"limit":{"type":"number","description":"Maximum number of results to return (default: 20)"}},"required":["query"],"$schema":"http://json-schema.org/draft-07/schema#"}},{"name":"compete_status","description":"Get an overview of the competitive intelligence system: competitor count, monitor count, signal counts by severity, and last fetch time.","parameters":{"type":"object","properties":{},"$schema":"http://json-schema.org/draft-07/schema#"}}]'::jsonb, 'raijinlabs/lucid-skills', 'first-party', true) ON CONFLICT (slug) DO UPDATE SET name=EXCLUDED.name, description=EXCLUDED.description, version=EXCLUDED.version, category=EXCLUDED.category, tool_manifest=EXCLUDED.tool_manifest, source_repo=EXCLUDED.source_repo, source=EXCLUDED.source, verified=EXCLUDED.verified;
INSERT INTO plugin_catalog (slug, name, description, version, category, tool_manifest, source_repo, source, verified) VALUES ('lucid-feedback', 'Lucid Feedback', 'Customer feedback intelligence: NPS, CSAT, sentiment analysis, surveys', '1.0.0', 'analytics', '[{"name":"feedback_submit","description":"Submit a new feedback entry. Automatically analyzes sentiment, categorizes content, and assigns priority if not provided.","parameters":{"type":"object","properties":{"content":{"type":"string","description":"The feedback text content"},"channel":{"type":"string","enum":["email","survey","nps","app_store","g2","trustpilot","twitter","support_ticket","intercom","manual"],"description":"Source channel of the feedback"},"category":{"type":"string","enum":["bug","feature_request","ux","performance","pricing","support","documentation","general"],"description":"Feedback category (auto-detected if omitted)"},"sentiment":{"type":"string","enum":["very_negative","negative","neutral","positive","very_positive"],"description":"Sentiment label (auto-detected if omitted)"},"rating":{"type":"number","minimum":1,"maximum":5,"description":"Star rating 1-5"},"nps_score":{"type":"number","minimum":0,"maximum":10,"description":"NPS score 0-10"},"author_name":{"type":"string","description":"Name of the feedback author"},"author_email":{"type":"string","description":"Email of the feedback author"},"priority":{"type":"string","enum":["low","medium","high","critical"],"description":"Priority level (auto-detected if omitted)"},"tags":{"type":"array","items":{"type":"string"},"description":"Tags to attach to the feedback"},"metadata":{"type":"object","propertyNames":{"type":"string"},"additionalProperties":{},"description":"Additional metadata"}},"required":["content"],"$schema":"http://json-schema.org/draft-07/schema#"}},{"name":"feedback_list","description":"List feedback entries with optional filters by channel, sentiment, category, status, priority, or search query.","parameters":{"type":"object","properties":{"channel":{"type":"string","enum":["email","survey","nps","app_store","g2","trustpilot","twitter","support_ticket","intercom","manual"],"description":"Filter by source channel"},"sentiment":{"type":"string","enum":["very_negative","negative","neutral","positive","very_positive"],"description":"Filter by sentiment"},"category":{"type":"string","enum":["bug","feature_request","ux","performance","pricing","support","documentation","general"],"description":"Filter by category"},"status":{"type":"string","enum":["new","reviewed","actioned","archived"],"description":"Filter by status"},"priority":{"type":"string","enum":["low","medium","high","critical"],"description":"Filter by priority"},"query":{"type":"string","description":"Text search query"},"limit":{"type":"number","minimum":1,"maximum":100,"description":"Max results (default 20)"},"offset":{"type":"number","minimum":0,"description":"Pagination offset"}},"$schema":"http://json-schema.org/draft-07/schema#"}},{"name":"feedback_analyze_sentiment","description":"Analyze the sentiment of a feedback text. Returns sentiment label (positive/negative/neutral), confidence score, detected keywords, category, and urgency.","parameters":{"type":"object","properties":{"text":{"type":"string","description":"The text to analyze for sentiment"}},"required":["text"],"$schema":"http://json-schema.org/draft-07/schema#"}},{"name":"feedback_get_nps","description":"Calculate the Net Promoter Score (NPS) with breakdown of promoters, passives, and detractors. Optionally filter by time period.","parameters":{"type":"object","properties":{"days":{"type":"number","minimum":1,"maximum":365,"description":"Number of days to look back (default: all time)"}},"$schema":"http://json-schema.org/draft-07/schema#"}},{"name":"feedback_get_csat","description":"Calculate the Customer Satisfaction (CSAT) score over a time period. CSAT is the percentage of ratings that are 4 or 5 out of 5.","parameters":{"type":"object","properties":{"days":{"type":"number","minimum":1,"maximum":365,"description":"Number of days to look back (default: 30)"}},"$schema":"http://json-schema.org/draft-07/schema#"}},{"name":"feedback_track_feature_request","description":"Create a new feature request or update an existing feedback item to mark it as a feature request. Assigns priority based on content analysis.","parameters":{"type":"object","properties":{"content":{"type":"string","description":"Description of the feature request"},"feedback_id":{"type":"number","description":"Existing feedback ID to convert to a feature request"},"priority":{"type":"string","enum":["low","medium","high","critical"],"description":"Priority level (auto-detected if omitted)"},"author_name":{"type":"string","description":"Name of the requester"},"tags":{"type":"array","items":{"type":"string"},"description":"Tags for the feature request"}},"required":["content"],"$schema":"http://json-schema.org/draft-07/schema#"}},{"name":"feedback_list_feature_requests","description":"List feature requests extracted from feedback, ranked by priority and frequency. Helps product teams identify the most-requested features.","parameters":{"type":"object","properties":{"priority":{"type":"string","enum":["low","medium","high","critical"],"description":"Minimum priority level to include"},"limit":{"type":"number","minimum":1,"maximum":100,"description":"Max results (default 20)"}},"$schema":"http://json-schema.org/draft-07/schema#"}},{"name":"feedback_get_trends","description":"Analyze feedback trends over time. Detects volume changes, sentiment shifts, and anomalies. Groups data by day, week, or month.","parameters":{"type":"object","properties":{"days":{"type":"number","minimum":7,"maximum":365,"description":"Number of days to analyze (default: 30)"},"period":{"type":"string","enum":["day","week","month"],"description":"Grouping period (default: week)"}},"$schema":"http://json-schema.org/draft-07/schema#"}},{"name":"feedback_categorize","description":"Auto-categorize feedback text by topic/type. Can also update an existing feedback item with the detected category.","parameters":{"type":"object","properties":{"text":{"type":"string","description":"Text to categorize (if no feedback_id)"},"feedback_id":{"type":"number","description":"Existing feedback ID to categorize and update"}},"$schema":"http://json-schema.org/draft-07/schema#"}},{"name":"feedback_get_insights","description":"Generate AI-ready structured insights from the entire feedback corpus. Combines NPS, themes, trends, and feature requests into a comprehensive summary.","parameters":{"type":"object","properties":{"days":{"type":"number","minimum":7,"maximum":365,"description":"Number of days to analyze (default: 30)"}},"$schema":"http://json-schema.org/draft-07/schema#"}},{"name":"feedback_create_survey","description":"Create a new feedback survey with customizable questions. Supports text, rating, NPS, and multiple choice question types.","parameters":{"type":"object","properties":{"name":{"type":"string","description":"Name of the survey"},"channel":{"type":"string","enum":["email","survey","nps","app_store","g2","trustpilot","twitter","support_ticket","intercom","manual"],"description":"Distribution channel (default: survey)"},"questions":{"type":"array","items":{"type":"object","properties":{"id":{"type":"string","description":"Unique question ID"},"text":{"type":"string","description":"Question text"},"type":{"type":"string","enum":["text","rating","nps","multiple_choice"],"description":"Question type"},"options":{"type":"array","items":{"type":"string"},"description":"Options for multiple_choice questions"},"required":{"type":"boolean","description":"Whether the question is required"}},"required":["id","text","type"]},"description":"Array of questions, each with id, text, type, and optional options"}},"required":["name","questions"],"$schema":"http://json-schema.org/draft-07/schema#"}},{"name":"feedback_status","description":"System health and statistics: total feedback count, survey count, response count, configuration status, and scheduler info.","parameters":{"type":"object","properties":{},"$schema":"http://json-schema.org/draft-07/schema#"}}]'::jsonb, 'raijinlabs/lucid-skills', 'first-party', true) ON CONFLICT (slug) DO UPDATE SET name=EXCLUDED.name, description=EXCLUDED.description, version=EXCLUDED.version, category=EXCLUDED.category, tool_manifest=EXCLUDED.tool_manifest, source_repo=EXCLUDED.source_repo, source=EXCLUDED.source, verified=EXCLUDED.verified;
